          />
        )}
        {recurringMessage && upgradeFrequency && !displayFrequencyAsCheckbox ? (
          <div className="mt-3 flex w-full justify-stretch">
            <RecurringUpgradeBanner
              frequency={upgradeFrequency}
              isChecked={selectedFrequency === upgradeFrequency}
              message={recurringMessage}
            />
          </div>
        ) : null}
        <AmountPresetsContainer
          actionButtonBgColor={actionButtonBgColor}
          actionButtonHoverBgColor={actionButtonHoverBgColor}
          actionButtonProps={actionButtonProps}
          actionButtonTextColor={actionButtonTextColor}
          amountPresetsOther={amountPresetsOther}
          amounts={resolvedAmounts}
          maximumAmount={transactionLimit}
          minimumAmount={transactionMinimum}
          otherAmount={otherAmount}
          selectedAmount={selectedAmount}
          setOtherAmount={setOtherAmount}
          setSelectedAmount={setSelectedAmount}
          setShowOtherInput={setShowOtherInput}
          showLoadingOnAmounts={showLoadingOnAmounts}
          showOtherInput={showOtherInput}
          ticketAmount={ticketAmount}
          totalFees={totalFees}
        />
        {isGiftOfAnyAmountAlertDisplayed && (
          <div className="mt-4">
            <GoaaAlert
              minimumGiftAmount={minimumGiftAmount}
              productsForRecurringOnly={productsForRecurringOnly}
            />
          </div>
        )}
        {showFundsAndAmounts &&
          (additionalFunds.length > 0 ||
            funds.length > 1 ||
            funds[0]?.accountConnectionFunds?.some((c) => c.accountId === primaryAccountId)) && (
            <FundsAndAmountsContainer
              addFund={addFund}
              additionalFunds={additionalFunds}
              allowModificationsOfFunds={allowModificationsOfFunds}
              amountAllocations={amountAllocations}
              amounts={resolvedAmounts}
              className="mt-4"
              funds={funds}
              key={multiFundExpanded?.toString()}
              multiFundExpanded={multiFundExpanded}
              primaryAccountId={primaryAccountId}
              removeFund={removeFund}
              setAllocationAmount={setAllocationAmount}
              setOtherAmount={setOtherAmount}
              setShowOtherInput={setShowOtherInput}
            />
          )}
        {isGiftOfAnyAmountAlertDisplayed && products && products.length > 0 ? (
          <ProductRadioGroup
            isDisabled={!isGiftOfAnyAmountAvailable}
            onChange={(id) => setSelectedProduct?.(products?.find((p) => p.id === id))}
            products={products}
            showMaximizeDonation={!goaaForceSelection}
            value={selectedProductValue}
          />
        ) : null}
        {upgradeFrequency && displayFrequencyAsCheckbox ? (
          <div className="mt-4 flex w-full justify-stretch">
            <RecurringUpgradeBanner
              displayFrequencyAsCheckbox
              frequency={upgradeFrequency}
              isChecked={selectedFrequency === upgradeFrequency}
              message={recurringMessage}
              onClick={onToggleRecurring}
            />
          </div>
        ) : null}
        {futurePledgeDate &&
          amount &&
          selectedFrequency === SourceFrequency.Once &&
          isAfter(parseDate(futurePledgeDate), new Date()) && (
            <FuturePledgeBanner
              amount={amount}
              date={futurePledgeDate}
              isChecked={futurePledgeSelected}
              message={futurePledgeMessage}
              onClick={() => setFuturePledgeSelected?.(!futurePledgeSelected)}
            />
          )}
      </div>
    </div>
  );
};

